import { useEffect, useMemo, useState } from "react";
import { useSearchParams } from "react-router-dom";
import { addTransaction, getCustomers, getTransactions } from "../services/api";
import "../styles/TransactionPage.css";

function TransactionPage() {
  const [searchParams] = useSearchParams();
  const initialCustomerId = searchParams.get("customerId") || "";

  const [customers, setCustomers] = useState([]);
  const [formData, setFormData] = useState({
    customerId: initialCustomerId,
    amount: "",
    type: "CREDIT",
    date: new Date().toISOString().split("T")[0],
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [message, setMessage] = useState("");
  const [messageType, setMessageType] = useState("");
  const [transactions, setTransactions] = useState([]);
  const [historyLoading, setHistoryLoading] = useState(false);

  useEffect(() => {
    // Loads customers to populate dropdown.
    const loadCustomers = async () => {
      try {
        const response = await getCustomers();
        setCustomers(response.data || []);
      } catch (error) {
        setCustomers([]);
      }
    };

    loadCustomers();
  }, []);

  useEffect(() => {
    // Fetches customer-specific transaction history.
    const loadHistory = async () => {
      if (!formData.customerId) {
        setTransactions([]);
        return;
      }

      try {
        setHistoryLoading(true);
        const response = await getTransactions(formData.customerId);
        setTransactions(response.data || []);
      } catch (error) {
        setTransactions([]);
      } finally {
        setHistoryLoading(false);
      }
    };

    loadHistory();
  }, [formData.customerId]);

  const selectedCustomerName = useMemo(() => {
    const found = customers.find((customer) => customer._id === formData.customerId);
    return found ? found.name : "None selected";
  }, [customers, formData.customerId]);

  const handleChange = (event) => {
    const { name, value } = event.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    setMessage("");

    if (!formData.customerId || !formData.amount || Number(formData.amount) <= 0) {
      setMessageType("danger");
      setMessage("Please select a customer and enter a valid amount.");
      return;
    }

    try {
      setIsSubmitting(true);
      await addTransaction({
        customerId: formData.customerId,
        amount: Number(formData.amount),
        type: formData.type,
        date: formData.date,
      });

      setMessageType("success");
      setMessage("Transaction recorded successfully.");
      setFormData((prev) => ({
        ...prev,
        amount: "",
        type: "CREDIT",
      }));
      const response = await getTransactions(formData.customerId);
      setTransactions(response.data || []);
    } catch (error) {
      setMessageType("danger");
      setMessage(error.response?.data?.message || "Failed to add transaction.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <main className="transaction-page py-4">
      <div className="container">
        <section className="transaction-header mb-4">
          <h1 className="transaction-title">Add Transaction</h1>
          <p className="transaction-subtitle">
            Update customer balance with a credit entry or payment collection.
          </p>
        </section>

        <section className="transaction-form-card card border-0 shadow-sm">
          <div className="card-body p-4">
            {message && <div className={`alert alert-${messageType}`}>{message}</div>}

            <form onSubmit={handleSubmit}>
              <div className="row g-3">
                <div className="col-md-6">
                  <label htmlFor="customerId" className="form-label">
                    Customer
                  </label>
                  <select
                    id="customerId"
                    name="customerId"
                    className="form-select"
                    value={formData.customerId}
                    onChange={handleChange}
                    required
                  >
                    <option value="">Choose customer</option>
                    {customers.map((customer) => (
                      <option key={customer._id} value={customer._id}>
                        {customer.name} ({customer.phone})
                      </option>
                    ))}
                  </select>
                  <p className="selected-customer mt-2 mb-0">Selected: {selectedCustomerName}</p>
                </div>

                <div className="col-md-3">
                  <label htmlFor="type" className="form-label">
                    Type
                  </label>
                  <select
                    id="type"
                    name="type"
                    className="form-select"
                    value={formData.type}
                    onChange={handleChange}
                  >
                    <option value="CREDIT">Credit</option>
                    <option value="PAYMENT">Payment</option>
                  </select>
                </div>

                <div className="col-md-3">
                  <label htmlFor="amount" className="form-label">
                    Amount (Rs)
                  </label>
                  <input
                    id="amount"
                    type="number"
                    min="1"
                    name="amount"
                    className="form-control"
                    value={formData.amount}
                    onChange={handleChange}
                    placeholder="Enter amount"
                    required
                  />
                </div>

                <div className="col-md-4">
                  <label htmlFor="date" className="form-label">
                    Date
                  </label>
                  <input
                    id="date"
                    type="date"
                    name="date"
                    className="form-control"
                    value={formData.date}
                    onChange={handleChange}
                  />
                </div>
              </div>

              <div className="mt-4">
                <button type="submit" className="btn submit-btn" disabled={isSubmitting}>
                  {isSubmitting ? "Saving..." : "Save Transaction"}
                </button>
              </div>
            </form>
          </div>
        </section>

        <section className="transaction-history-card card border-0 shadow-sm mt-4">
          <div className="card-body p-4">
            <h2 className="history-title">Recent Transactions</h2>
            <div className="table-responsive">
              <table className="table transaction-history-table mb-0">
                <thead>
                  <tr>
                    <th>Date</th>
                    <th>Type</th>
                    <th>Amount</th>
                  </tr>
                </thead>
                <tbody>
                  {!formData.customerId ? (
                    <tr>
                      <td colSpan="3" className="text-center py-3">
                        Select a customer to view transaction history.
                      </td>
                    </tr>
                  ) : historyLoading ? (
                    <tr>
                      <td colSpan="3" className="text-center py-3">
                        Loading transactions...
                      </td>
                    </tr>
                  ) : transactions.length === 0 ? (
                    <tr>
                      <td colSpan="3" className="text-center py-3">
                        No transactions found for this customer.
                      </td>
                    </tr>
                  ) : (
                    transactions.map((transaction) => (
                      <tr key={transaction._id}>
                        <td>{new Date(transaction.date).toLocaleDateString("en-IN")}</td>
                        <td>{transaction.type}</td>
                        <td>Rs {Number(transaction.amount).toLocaleString("en-IN")}</td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </section>
      </div>
    </main>
  );
}

export default TransactionPage;
